body.script:
;(function($, window, document, undefined) {
    $(document).ready(function() {
    	let $searchResult = $('.search-result');
    	if($searchResult.length > 0) {
    		sortSearchResult();
    	}
		function sortSearchResult() {
			let $searchResult = $('.search-result');
			let searchQuery = $searchResult.find('input[type="search"]').val();
			let $searchedItems = $searchResult.find('.searched-item');
			let $resultsList = $searchResult.find('.results');
			$searchedItems.each(function() {
				let $this = $(this);
				if($this.data('title').indexOf(searchQuery.toUpperCase()) !== -1) {
					$this.prependTo($resultsList);
				}
			});
		}
    });
})(jQuery, window, document);

